import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import 'react-phone-number-input/style.css'
import PhoneInput from 'react-phone-number-input'
import { TextField, FormGroup, FormControl, FormLabel, Typography, Button } from '@material-ui/core';
import { appActions, alertAction } from '../../../actions';
import { trackerUtil, trackerActions, onEnterPress } from '../utils';
import { routeNamesTracker } from '../routeNames';


const style = theme => ({
    root: {
        background : "url('./images/background_map.jpg') no-repeat center center",
        backgroundSize : "cover",
        height : "100vh",
        width : "100vw",
    },
    overLay : {
        height : "100%",
        width : "100%",
        backgroundColor : trackerUtil.getTheme().primaryTrans,
        display : "flex",
        alignItems : "center",
        justifyContent : "center"
    },
    formContainer : {
        backgroundColor : trackerUtil.getTheme().primary, 
        padding : 20,
        borderRadius : 10,
        width : "50%",
        [theme.breakpoints.down("xs")] : {
            width : "80%"
        },
        [theme.breakpoints.up("md")] : {
            width : "30%",
        }
    },
    textField : {
        background : trackerUtil.getTheme().white,
        borderRadius : 5,
        border : "none"
    },
    noBorder : {
        border : "none"
    },
    headerContainer : {
        marginBottom : 50,
    },
    header : {
        color : trackerUtil.getTheme().white,
        fontWeight : "bold"
    },
    loginButton : {
        marginTop : 20,
        backgroundColor : trackerUtil.getTheme().primary,
        color : trackerUtil.getTheme().white
    }
})
class _Signup extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : {
                name : "",
                phone : "",
                email : "",
                password : "",
            },
            loading : false
        }
    }
    handleChange=name=>event=>{
        let value;
        if(name === "phone")
            value = event;
        else 
            value = event.target.value;
        let data = {...this.state.data};
        data[name] = value;
        this.setState({data});
    }
    signup(){
        this.setState({loading: true});
        const {data} = this.state;
        let decision = {
            continue : true
        };
        Object.entries(data).map(item=>{
            if(item[1].trim() === ""){
                appActions.showSnackbar(
                    alertAction.error("Empty field error!")
                )(this.props.dispatch);
                decision.continue = false;
                this.setState({loading: false});
                return;
            }
        });
        if(decision.continue){
            trackerActions.signup(data, done => {
                this.setState({loading: false});
                if(done) this.props.history.replace(routeNamesTracker.dashboard);
            })(this.props.dispatch);
        }
        
    }
    render() {
        const {classes} = this.props;
        const {loading, data} = this.state;
        const {name, email, phone, password} = data;
        return (
            <div className={classes.root}>
                <div className={classes.overLay}>
                    <div className={classes.formContainer}>
                        <FormGroup>
                            <FormLabel className={classes.headerContainer}>
                                <Typography className={classes.header} component="h4" variant="h4">Sign up</Typography>
                            </FormLabel>
                            <FormControl>
                                <TextField
                                    label="Name"
                                    placeholder="Name"
                                    margin="normal"
                                    onChange={this.handleChange("name")}
                                    value={name || ""}
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.signup.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <PhoneInput
                                    className={classes.textField}
                                    style={{
                                        marginTop : 20,
                                        marginBottom : 10,
                                        padding : 10,
                                        borderRadius : 5
                                    }}
                                    placeholder="Enter phone number"
                                    value={phone || ""}
                                    onChange={ this.handleChange("phone")} 
                                    onKeyDown={onEnterPress(this.signup.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <TextField
                                    label="Email"
                                    placeholder="Email"
                                    margin="normal"
                                    onChange={this.handleChange("email")}
                                    value={email || ""}
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.signup.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <TextField
                                    label="Password"
                                    placeholder="password"
                                    margin="normal"
                                    onChange={this.handleChange("password")}
                                    value={password || ""}
                                    type="password"
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.signup.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <Button
                                    disabled={loading}
                                    className={classes.loginButton}
                                    onClick={()=>this.signup()}>
                                        Sign up
                                    </Button>
                            </FormControl>
                            <div style={{marginTop : 20}}>
                                <Button
                                    className={classes.loginButton}
                                    variant="text"
                                    onClick={()=>this.props.history.replace(routeNamesTracker.login)}>
                                        Login
                                    </Button>
                            </div>
                        </FormGroup>
                    </div>
                </div>            
            </div>
        );
    }
}


_Signup.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const Signup = connect(mapStateToProps)(withStyles(style)(_Signup));
export {Signup as default}